// Helper functions
function getBooksByCategory(cat) {
  return BOOKS_DATA.filter(b => b.category === cat);
}

function getFeaturedBooks() {
  return BOOKS_DATA.filter(b => b.featured);
}

function getLatestBooks(n = 6) {
  return [...BOOKS_DATA].slice(-n).reverse();
}

function getBookBySlug(slug) {
  return BOOKS_DATA.find(b => b.slug === slug);
}

function getCategoryBookCount(cat) {
  return BOOKS_DATA.filter(b => b.category === cat).length;
}
